class {{prefix_nama}}Error(Exception):
    """Base exception untuk semua error LLM API."""


class {{prefix_nama}}RateLimitError({{prefix_nama}}Error):
    """Dipicu saat API mengembalikan status 429 (rate limit tercapai)."""


class {{prefix_nama}}TimeoutError({{prefix_nama}}Error):
    """Dipicu saat koneksi atau baca respons melebihi batas waktu."""


class {{prefix_nama}}InvalidResponseError({{prefix_nama}}Error):
    """Dipicu saat respons API tidak bisa diparsing atau strukturnya tidak sesuai."""


class {{prefix_nama}}AuthError({{prefix_nama}}Error):
    """Dipicu saat API key tidak valid atau tidak punya izin (401/403)."""


def classify_http_error(status_code, message=""):
    """Ubah kode status HTTP menjadi exception hierarki yang tepat."""
    if status_code == 429:
        raise {{prefix_nama}}RateLimitError(f"Rate limit: {message}")
    if status_code in (401, 403):
        raise {{prefix_nama}}AuthError(f"Auth gagal ({status_code}): {message}")
    if status_code >= 400:
        raise {{prefix_nama}}Error(f"HTTP {status_code}: {message}")

class {{nama_kelas}}:
    """Circuit breaker: blokir panggilan sementara setelah {{failure_threshold}} kegagalan berturut-turut.
    Coba pulih setelah {{recovery_timeout}} detik.
    """

    CLOSED = "closed"      # Normal, panggilan diizinkan
    OPEN = "open"          # Gagal terlalu banyak, panggilan diblokir
    HALF_OPEN = "half_open"  # Sedang uji coba pemulihan

    def __init__(self):
        self.state = self.CLOSED
        self._failure_count = 0
        self._last_failure_time = None

    def call(self, func, *args, **kwargs):
        """Jalankan func melalui circuit breaker. Lempar RuntimeError jika circuit terbuka."""
        if self.state == self.OPEN:
            elapsed = time.time() - self._last_failure_time
            if elapsed >= {{recovery_timeout}}:
                self.state = self.HALF_OPEN
            else:
                raise RuntimeError(
                    f"Circuit terbuka. Coba lagi dalam "
                    f"{{{recovery_timeout}} - elapsed:.0f} detik."
                )
        try:
            result = func(*args, **kwargs)
            self._on_success()
            return result
        except Exception as exc:
            self._on_failure()
            raise exc

    def _on_success(self):
        self._failure_count = 0
        self.state = self.CLOSED

    def _on_failure(self):
        self._failure_count += 1
        self._last_failure_time = time.time()
        if self._failure_count >= {{failure_threshold}}:
            self.state = self.OPEN

def {{nama_fungsi}}(providers, *args, **kwargs):
    """Coba tiap callable di providers secara berurutan.
    providers: list of callable, masing-masing menerima *args, **kwargs.
    Kembalikan hasil dari provider pertama yang berhasil.
    Lempar Exception terakhir jika semua gagal.
    """
    last_error = None
    for idx, provider_func in enumerate(providers):
        try:
            return provider_func(*args, **kwargs)
        except Exception as exc:
            last_error = exc
            provider_name = getattr(provider_func, "__name__", f"provider_{idx}")
            print(f"[fallback] {provider_name} gagal: {exc}. Mencoba berikutnya...")
    raise RuntimeError(
        f"Semua {len(providers)} provider gagal. Error terakhir: {last_error}"
    )
